@WebService(name = "EmployeeManagementService", targetNamespace = "http://hr.system.com/")
public class EmployeeManagementService {
    
    private Map<String, Employee> employeeDatabase = new HashMap<>();
    
    public EmployeeManagementService() {
        // Initialize with some sample data
        employeeDatabase.put("EMP001", new Employee("EMP001", "John Doe", 50000.0, "Developer"));
        employeeDatabase.put("EMP002", new Employee("EMP002", "Jane Smith", 60000.0, "Manager"));
    }
    
    @WebMethod(operationName = "updateSalary")
    @WebResult(name = "salaryUpdateResult")
    public SalaryUpdateResponse updateSalary(
            @WebParam(name = "employeeId") String employeeId,
            @WebParam(name = "newSalary") double newSalary) {
        
        Employee employee = employeeDatabase.get(employeeId);
        if (employee != null) {
            double oldSalary = employee.getSalary();
            employee.setSalary(newSalary);
            return new SalaryUpdateResponse(true, "Salary updated successfully", oldSalary, newSalary);
        } else {
            return new SalaryUpdateResponse(false, "Employee not found", 0.0, 0.0);
        }
    }
    
    @WebMethod(operationName = "performPerformanceReview")
    @WebResult(name = "performanceReviewResult")
    public PerformanceReviewResponse performPerformanceReview(
            @WebParam(name = "employeeId") String employeeId,
            @WebParam(name = "reviewComments") String reviewComments,
            @WebParam(name = "performanceRating") int performanceRating) {
        
        Employee employee = employeeDatabase.get(employeeId);
        if (employee != null) {
            return new PerformanceReviewResponse(true, "Performance review completed", 
                                               employee.getEmployeeId(), 
                                               employee.getName(), 
                                               performanceRating, 
                                               reviewComments);
        } else {
            return new PerformanceReviewResponse(false, "Employee not found", 
                                               null, null, 0, null);
        }
    }
    
    @WebMethod(operationName = "terminateEmployee")
    @WebResult(name = "terminationResult")
    public TerminationResponse terminateEmployee(
            @WebParam(name = "employeeId") String employeeId,
            @WebParam(name = "terminationReason") String terminationReason) {
        
        Employee employee = employeeDatabase.get(employeeId);
        if (employee != null) {
            employeeDatabase.remove(employeeId);
            return new TerminationResponse(true, "Employee terminated successfully", 
                                         employee.getEmployeeId(), 
                                         employee.getName(), 
                                         terminationReason);
        } else {
            return new TerminationResponse(false, "Employee not found", 
                                         null, null, terminationReason);
        }
    }
    
    @WebMethod(operationName = "getEmployeeDetails")
    @WebResult(name = "employeeDetails")
    public Employee getEmployeeDetails(@WebParam(name = "employeeId") String employeeId) {
        return employeeDatabase.get(employeeId);
    }
}

